244→    const handleSubmit = async(e) =>{
245→        e.stopPropagation();
246→        e.preventDefault();
247→        try {
248→            setUploadingUserData(true)
249→            const formdata = new FormData();
250→            if(imageFile){
251→                formdata.append('image', imageFile);
252→            }
253→            if(bio && name){
254→                formdata.append('name', name)
255→                formdata.append('bio', bio)
256→                if(setupUsername && setupUsername.length >= 3){
257→                    formdata.append('username', setupUsername)
258→                }
259→            }
260→            const {data} = await submitProfileData(formdata, session?.access_token);
261→            // if(data){
262→            //     console.log(data)
263→            // }
264→            setShowWelcomeMessage(true)
265→        } catch (error) {
266→            throw new Error('error uploading data')
267→        } finally {
268→            setBio('')
269→            setName('')
270→            setSetupUsername('')
271→            setUsernameAvailable(null)
272→            setImageFile(null)
273→            setProfilePreview('')
274→            setUploadingUserData(false)
275→            setShowProfileEditor(false)
276→            queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
277→            
278→        }
279→        
280→    }
