                    </g>
                </g>
            </svg>
        },
        {
            path: '/home/settings',
            label: 'Settings',
            action: () => navigatePath('/home/settings'),
            icon:
            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={location.pathname === '/home/settings' ? "#5f92ff" : "#b6b6b6"}>
                <path d="M12 15.5A3.5 3.5 0 1 0 12 8.5a3.5 3.5 0 0 0 0 7Z"/>
