  1→import { useState, useRef, useCallback } from 'react';
  2→import { motion, AnimatePresence, LayoutGroup } from 'framer-motion';
  3→import { useAuth } from '../../Context/useAuth';
  4→import { submitProfileData, checkUsernameAvailability, completeOnboarding } from '../../../API/Api';
  5→import { useQueryClient } from '@tanstack/react-query';
  6→
  7→import StepProgressBar from './components/StepProgressBar';
  8→import WelcomeStep from './steps/WelcomeStep';
  9→import ProfileSetupStep from './steps/ProfileSetupStep';
 10→import InterestsStep from './steps/InterestsStep';
 11→import FeatureShowcaseStep from './steps/FeatureShowcaseStep';
 12→import FirstActionStep from './steps/FirstActionStep';
 13→
 14→import './OnboardingWizard.css';
 15→
 16→const TOTAL_STEPS = 5;
 17→
 18→const slideVariants = {
 19→    enter: (direction) => ({
 20→        x: direction > 0 ? 80 : -80,
 21→        opacity: 0,
 22→    }),
 23→    center: {
 24→        x: 0,
 25→        opacity: 1,
 26→    },
 27→    exit: (direction) => ({
 28→        x: direction > 0 ? -80 : 80,
 29→        opacity: 0,
 30→    }),
 31→};
 32→
 33→const slideTransition = {
 34→    type: 'spring',
 35→    stiffness: 350,
 36→    damping: 32,
 37→    mass: 0.8,
 38→};
 39→
 40→const OnboardingWizard = ({ onComplete, userExists }) => {
 41→    const { session, user } = useAuth();
 42→    const queryClient = useQueryClient();
 43→
 44→    const [currentStep, setCurrentStep] = useState(userExists ? 2 : 0);
 45→    const [direction, setDirection] = useState(1);
 46→
 47→    // Profile state
 48→    const [name, setName] = useState('');
 49→    const [bio, setBio] = useState('');
 50→    const [setupUsername, setSetupUsername] = useState('');
 51→    const [usernameAvailable, setUsernameAvailable] = useState(null);
 52→    const [usernameChecking, setUsernameChecking] = useState(false);
 53→    const usernameCheckTimer = useRef(null);
 54→    const [profilePreview, setProfilePreview] = useState(null);
 55→    const [imageFile, setImageFile] = useState(null);
 56→    const [submitting, setSubmitting] = useState(false);
 57→
 58→    // Interests state
 59→    const [writingInterests, setWritingInterests] = useState([]);
 60→    const [writingGoal, setWritingGoal] = useState('');
 61→
 62→    const checkUsernameDebounced = useCallback((uname) => {
 63→        if (usernameCheckTimer.current) clearTimeout(usernameCheckTimer.current);
 64→        if (!uname || uname.length < 3) {
 65→            setUsernameAvailable(null);
 66→            return;
 67→        }
 68→        setUsernameChecking(true);
 69→        usernameCheckTimer.current = setTimeout(async () => {
 70→            try {
 71→                const result = await checkUsernameAvailability(uname);
 72→                setUsernameAvailable(result.available);
 73→            } catch {
 74→                setUsernameAvailable(null);
 75→            } finally {
 76→                setUsernameChecking(false);
 77→            }
 78→        }, 400);
 79→    }, []);
 80→
 81→    const goNext = useCallback(() => {
 82→        setDirection(1);
 83→        setCurrentStep((s) => Math.min(s + 1, TOTAL_STEPS - 1));
 84→    }, []);
 85→
 86→    const goBack = useCallback(() => {
 87→        setDirection(-1);
 88→        setCurrentStep((s) => Math.max(s - 1, 0));
 89→    }, []);
 90→
 91→    const handleSubmitProfile = useCallback(async () => {
 92→        try {
 93→            setSubmitting(true);
 94→            const formdata = new FormData();
 95→            if (imageFile) formdata.append('image', imageFile);
 96→            if (bio && name) {
 97→                formdata.append('name', name);
 98→                formdata.append('bio', bio);
 99→                if (setupUsername && setupUsername.length >= 3) {
100→                    formdata.append('username', setupUsername);
101→                }
102→            }
103→            await submitProfileData(formdata, session?.access_token);
104→            queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
105→        } catch (error) {
106→            console.error('error uploading profile data:', error);
107→        } finally {
108→            setSubmitting(false);
109→        }
110→    }, [imageFile, bio, name, setupUsername, session, queryClient]);
111→
112→    const handleComplete = useCallback(async (action) => {
113→        try {
114→            await completeOnboarding(session?.access_token, {
115→                writingInterests,
116→                writingGoal,
117→            });
118→        } catch (err) {
119→            console.error('non-fatal: failed to save onboarding preferences:', err);
120→        }
121→        queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
122→        onComplete(action);
123→    }, [session, writingInterests, writingGoal, queryClient, onComplete]);
124→
125→    const renderStep = () => {
126→        switch (currentStep) {
127→            case 0:
128→                return <WelcomeStep key="welcome" goNext={goNext} />;
129→            case 1:
130→                return (
131→                    <ProfileSetupStep
132→                        key="profile"
133→                        goNext={goNext}
134→                        goBack={goBack}
135→                        name={name}
136→                        setName={setName}
137→                        bio={bio}
138→                        setBio={setBio}
139→                        setupUsername={setupUsername}
140→                        setSetupUsername={setSetupUsername}
141→                        usernameAvailable={usernameAvailable}
142→                        usernameChecking={usernameChecking}
143→                        profilePreview={profilePreview}
144→                        setProfilePreview={setProfilePreview}
145→                        imageFile={imageFile}
146→                        setImageFile={setImageFile}
147→                        checkUsernameDebounced={checkUsernameDebounced}
148→                        submitting={submitting}
149→                        onSubmitProfile={handleSubmitProfile}
150→                    />
151→                );
152→            case 2:
153→                return (
154→                    <InterestsStep
155→                        key="interests"
156→                        goNext={goNext}
157→                        goBack={userExists ? undefined : goBack}
158→                        writingInterests={writingInterests}
159→                        setWritingInterests={setWritingInterests}
160→                        writingGoal={writingGoal}
161→                        setWritingGoal={setWritingGoal}
162→                    />
163→                );
164→            case 3:
165→                return <FeatureShowcaseStep key="showcase" goNext={goNext} goBack={goBack} />;
166→            case 4:
167→                return (
168→                    <FirstActionStep
169→                        key="firstaction"
170→                        goBack={goBack}
171→                        writingGoal={writingGoal}
172→                        onComplete={handleComplete}
173→                    />
174→                );
175→            default:
176→                return null;
177→        }
178→    };
179→
180→    return (
181→        <div className="onboarding-wizard-overlay">
182→            <div className="onboarding-wizard-card">
183→                <LayoutGroup>
184→                    <StepProgressBar currentStep={currentStep} totalSteps={TOTAL_STEPS} />
185→                </LayoutGroup>
186→
187→                <div className="onboarding-wizard-content">
188→                    <AnimatePresence mode="wait" custom={direction}>
189→                        <motion.div
190→                            key={currentStep}
191→                            custom={direction}
192→                            variants={slideVariants}
193→                            initial="enter"
194→                            animate="center"
195→                            exit="exit"
196→                            transition={slideTransition}
197→                            className="onboarding-step-wrapper"
198→                        >
199→                            {renderStep()}
200→                        </motion.div>
201→                    </AnimatePresence>
202→                </div>
203→            </div>
204→        </div>
205→    );
206→};
207→
208→export default OnboardingWizard;
