 1→import { useState, useEffect } from 'react';
 2→
 3→const TypewriterText = ({ text, delay = 40, className = '', onComplete }) => {
 4→    const [displayed, setDisplayed] = useState('');
 5→    const [done, setDone] = useState(false);
 6→
 7→    useEffect(() => {
 8→        setDisplayed('');
 9→        setDone(false);
10→        let i = 0;
11→        const interval = setInterval(() => {
12→            i++;
13→            setDisplayed(text.slice(0, i));
14→            if (i >= text.length) {
15→                clearInterval(interval);
16→                setDone(true);
17→                onComplete?.();
18→            }
19→        }, delay);
20→        return () => clearInterval(interval);
21→    }, [text, delay]);
22→
23→    return (
24→        <span className={className}>
25→            {displayed}
26→            {!done && <span className="typewriter-cursor">|</span>}
27→        </span>
28→    );
29→};
30→
31→export default TypewriterText;
