/* ─── Welcome Step ───────────────────────────────────────── */

.welcome-step {
    padding: 32px 0 16px;
}

.welcome-blob {
    position: absolute;
    top: -40px;
    right: -40px;
    width: 180px;
    height: 180px;
    background: linear-gradient(135deg, rgba(212, 168, 83, 0.15), rgba(212, 168, 83, 0.05));
    border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%;
    animation: morph 20s ease-in-out infinite;
    pointer-events: none;
    z-index: 0;
}

@keyframes morph {
    0%, 100% { border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%; }
    25% { border-radius: 55% 45% 50% 50% / 60% 40% 60% 40%; }
    50% { border-radius: 40% 60% 55% 45% / 50% 55% 45% 50%; }
    75% { border-radius: 60% 40% 45% 55% / 45% 60% 40% 55%; }
}

.welcome-brand {
    font-family: "Playfair Display", Georgia, serif;
    font-size: 0.85rem;
    font-weight: 700;
    letter-spacing: 0.2em;
    color: var(--accent-amber, #D4A853);
    margin-bottom: 8px;
    z-index: 1;
}

.welcome-step .onboarding-step-title {
    font-size: 1.75rem;
    z-index: 1;
}

.welcome-step .onboarding-step-subtitle {
    font-size: 1rem;
    margin-bottom: 24px;
    z-index: 1;
}

.welcome-step .onboarding-cta-primary {
    max-width: 280px;
    z-index: 1;
}

.onboarding-confetti-canvas {
    position: fixed;
    inset: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    z-index: 999999;
}

.typewriter-cursor {
    display: inline-block;
    animation: blink-cursor 0.7s step-end infinite;
    color: var(--accent-amber, #D4A853);
    font-weight: 400;
    margin-left: 1px;
}

@keyframes blink-cursor {
    0%, 100% { opacity: 1; }
    50% { opacity: 0; }
}

/* ─── Profile Setup Step ─────────────────────────────────── */

.profile-setup-step {
    padding: 8px 0 0;
}

.profile-setup-form {
    display: flex;
    flex-direction: column;
    gap: 14px;
    width: 100%;
    margin-top: 8px;
}

.profile-setup-avatar-container {
    display: flex;
    justify-content: center;
    margin: 8px 0;
}

.profile-setup-avatar-wrapper {
    position: relative;
    width: 90px;
    height: 90px;
    cursor: pointer;
}

.profile-setup-avatar-img {
    width: 90px;
    height: 90px;
    border-radius: 50%;
    object-fit: cover;
}

.profile-setup-avatar-overlay {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    background: rgba(0, 0, 0, 0.35);
    opacity: 0;
    transition: opacity 0.2s ease;
}

.profile-setup-avatar-wrapper:hover .profile-setup-avatar-overlay {
    opacity: 1;
}

/* ─── Interests Step ─────────────────────────────────────── */

.interests-step {
    padding: 8px 0 0;
}

.interests-topic-grid {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    justify-content: center;
    margin: 8px 0 16px;
    width: 100%;
}

.interests-chip {
    padding: 8px 16px;
    border-radius: 20px;
    border: 1px solid var(--border-card);
    background: var(--bg-glass, var(--bg-primary));
    color: var(--text-body);
    font-family: var(--font-ui);
    font-size: 0.82rem;
    font-weight: 500;
    cursor: pointer;
    transition: border-color 0.2s ease, background-color 0.2s ease, color 0.2s ease, box-shadow 0.2s ease;
    user-select: none;
}

.interests-chip:hover {
    border-color: var(--accent-amber, #D4A853);
}

.interests-chip.selected {
    border-color: var(--accent-amber, #D4A853);
    background: rgba(212, 168, 83, 0.12);
    color: var(--accent-amber, #D4A853);
    font-weight: 600;
    box-shadow: 0 0 0 1px var(--accent-amber, #D4A853);
}

.interests-goal-heading {
    font-family: "Playfair Display", Georgia, serif;
    font-size: 1.05rem;
    font-weight: 600;
    color: var(--text-heading);
    margin: 4px 0 8px;
    text-align: center;
}

.interests-goal-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px;
    width: 100%;
    margin-bottom: 8px;
}

.interests-goal-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 6px;
    padding: 16px 8px;
    border-radius: 12px;
    border: 1px solid var(--border-card);
    background: var(--bg-glass, var(--bg-primary));
    cursor: pointer;
    transition: border-color 0.2s ease, background-color 0.2s ease, box-shadow 0.2s ease;
}

.interests-goal-card:hover {
    border-color: var(--accent-amber, #D4A853);
}

.interests-goal-card.selected {
    border-color: var(--accent-amber, #D4A853);
    background: rgba(212, 168, 83, 0.08);
    box-shadow: 0 0 0 1px var(--accent-amber, #D4A853);
}

.interests-goal-icon {
    color: var(--accent-amber, #D4A853);
    display: flex;
}

.interests-goal-label {
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 500;
    color: var(--text-body);
    text-align: center;
}

.interests-goal-card.selected .interests-goal-label {
    color: var(--text-heading);
    font-weight: 600;
}

/* ─── Feature Showcase Step ──────────────────────────────── */

.showcase-step {
    padding: 8px 0 0;
}

.showcase-features-grid {
    display: flex;
    flex-direction: column;
    gap: 12px;
    width: 100%;
    margin: 12px 0 8px;
}

.showcase-feature-card {
    display: flex;
    align-items: flex-start;
    gap: 14px;
    padding: 16px;
    border-radius: 12px;
    border: 1px solid var(--border-card);
    background: var(--bg-glass, var(--bg-primary));
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.showcase-feature-card:hover {
    border-color: rgba(212, 168, 83, 0.3);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.04);
}

.showcase-feature-icon {
    color: var(--accent-amber, #D4A853);
    flex-shrink: 0;
    display: flex;
    margin-top: 2px;
}

.showcase-feature-text {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.showcase-feature-title {
    font-family: var(--font-ui);
    font-size: 0.9rem;
    font-weight: 600;
    color: var(--text-heading);
    margin: 0;
}

.showcase-feature-desc {
    font-family: "Lora", Georgia, serif;
    font-style: italic;
    font-size: 0.82rem;
    line-height: 1.45;
    color: var(--text-muted);
    margin: 0;
}

/* ─── First Action Step ──────────────────────────────────── */

.firstaction-step {
    padding: 32px 0 16px;
}

.firstaction-icon {
    color: var(--accent-amber, #D4A853);
    margin-bottom: 8px;
}

.firstaction-step .onboarding-step-subtitle {
    margin-bottom: 20px;
}

.firstaction-cta-group {
    display: flex;
    flex-direction: column;
    width: 100%;
    max-width: 280px;
    gap: 6px;
}

/* ─── Reduced Motion ─────────────────────────────────────── */

@media (prefers-reduced-motion: reduce) {
    .welcome-blob {
        animation: none;
    }
    .typewriter-cursor {
        animation: none;
        opacity: 1;
    }
}

/* ─── Responsive ─────────────────────────────────────────── */

@media (max-width: 768px) {
    .onboarding-wizard-card {
        max-width: 92%;
        padding: 24px 20px 28px;
    }
}

@media (max-width: 480px) {
    .onboarding-wizard-card {
        max-width: 96%;
        padding: 20px 16px 24px;
        border-radius: 12px;
    }

    .onboarding-step-title {
        font-size: 1.3rem;
    }

    .onboarding-step-subtitle {
        font-size: 0.88rem;
    }

    .interests-topic-grid {
        gap: 6px;
    }

    .interests-chip {
        padding: 6px 12px;
        font-size: 0.78rem;
    }

    .welcome-step .onboarding-step-title,
    .welcome-step .welcome-title {
        font-size: 1.4rem;
    }

    .onboarding-progress-line {
        width: 20px;
    }
}

@media (max-width: 428px) {
    .onboarding-wizard-card {
        max-width: 100%;
        border-radius: 0;
        max-height: 100vh;
        height: 100vh;
        justify-content: center;
    }

    .interests-goal-grid {
        grid-template-columns: 1fr;
    }
}

