148→                        onChange={handleUsernameChange}
149→                        className="onboarding-input"
150→                        type="text"
151→                        placeholder="e.g. john-doe"
152→                    />
153→                </div>
154→
155→                <motion.button
156→                    type="submit"
157→                    className="onboarding-cta-primary"
158→                    disabled={!isValid || submitting}
159→                    whileHover={isValid ? { scale: 1.02 } : {}}
160→                    whileTap={isValid ? { scale: 0.98 } : {}}
161→                >
162→                    {submitting ? 'Saving...' : 'Continue'}
163→                </motion.button>
164→            </form>
165→        </div>
166→    );
167→};
168→
169→export default ProfileSetupStep;
