 25→        }, 300);
 26→
 27→        return () => clearTimeout(timer);
 28→    }, []);
 29→
 30→    const getPrimaryCta = () => {
 31→        switch (writingGoal) {
 32→            case 'journal':
 33→            case 'publish':
 34→                return { label: 'Write your first post', action: 'write' };
 35→            case 'stories':
 36→                return { label: 'Start a story', action: 'story' };
